        <div className="mt-1 h-2 overflow-hidden rounded-full bg-surface-700"><div className={`h-full rounded-full transition-all ${hpColor}`} style={{ width: `${hpPercent}%` }} /></div>
      </div>
      <div className="mt-3 grid grid-cols-6 gap-1">
        {ABILITY_ORDER.map((abbr) => <div key={abbr} className="rounded bg-surface-800 py-1 text-center"><p className="text-[10px] uppercase text-surface-500">{ABILITY_SHORT[abbr]}</p><p className="text-xs font-bold text-surface-200">{character.abilityScores[abbr]}</p></div>)}
