{"content": "/* ── Map Editor ─────────────────────────────────────────────────
 * Interactive battle map canvas with grid, tokens, fog of war,
 * background image support, zoom/pan, and click-to-place tokens.
 * ─────────────────────────────────────────────────────────────── */

import { useState, useRef, useCallback, useEffect, useMemo } from "react";
import { Button } from "@/components/ui/Button";
import type { BattleMap, MapToken, FogReveal } from "@/types";

interface MapEditorProps {
  map: BattleMap;
  /** Called when tokens are modified (moved, added, removed) */
  onTokensChange?: (tokens: MapToken[]) => void;
  /** Called when fog of war is modified */
  onFogChange?: (fog: FogReveal[]) => void;
  /** Read-only mode (for player view) */
  readOnly?: boolean;
}

function uid(prefix: string): string {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

export function MapEditor({ map, onTokensChange, onFogChange, readOnly = false }: MapEditorProps) {
  const { gridWidth, gridHeight, gridSize, imageUrl } = map;
  const cellSize = Math.min(gridSize, 48); // render cap

  // ── Canvas State ──
  const canvasRef = useRef<HTMLDivElement>(null);
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [panStart, setPanStart] = useState({ x: 0, y: 0 });
  const [hoveredCell, setHoveredCell] = useState<{ x: number; y: number } | null>(null);
  const [tokens, setTokens] = useState<MapToken[]>(map.tokens);
  const [fogOfWar, setFogOfWar] = useState<FogReveal[]>(map.fogOfWar);
  const [showFog, setShowFog] = useState(true);
  const [draggingToken, setDraggingToken] = useState<string | null>(null);
  const [selectedToken, setSelectedToken] = useState<string | null>(null);
  const [showGrid, setShowGrid] = useState(true);

  // Sync external changes
  useEffect(() => { setTokens(map.tokens); }, [map.tokens]);
  useEffect(() => { setFogOfWar(map.fogOfWar); }, [map.fogOfWar]);

  const notifyTokens = useCallback((newTokens: MapToken[]) => {
    setTokens(newTokens);
    onTokensChange?.(newTokens);
  }, [onTokensChange]);

  const notifyFog = useCallback((newFog: FogReveal[]) => {
    setFogOfWar(newFog);
    onFogChange?.(newFog);
  }, [onFogChange]);

  // ── Coordinate Helpers ──
  const toGridCoords = useCallback((clientX: number, clientY: number): { x: number; y: number } | null => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return null;
    const x = (clientX - rect.left - pan.x) / zoom;
    const y = (clientY - rect.top - pan.y) / zoom;
    const gx = Math.floor(x / cellSize);
    const gy = Math.floor(y / cellSize);
    if (gx < 0 || gx >= gridWidth || gy < 0 || gy >= gridHeight) return null;
    return { x: gx, y: gy };
  }, [cellSize, gridWidth, gridHeight, pan, zoom]);

  // ── Token Interaction ──
  const tokenAt = useCallback((gx: number, gy: number): MapToken | undefined => {
    return tokens.find(t => t.x === gx && t.y === gy);
  }, [tokens]);

  const addTokenAt = useCallback((gx: number, gy: number) => {
    if (readOnly) return;
    const newToken: MapToken = {
      id: uid("tk"),
      type: "custom",
      label: `Token ${tokens.length + 1}`,
      x: gx,
      y: gy,
      color: "#8b30ff",
      size: 1,
      visible: true,
    };
    notifyTokens([...tokens, newToken]);
    setSelectedToken(newToken.id);
  }, [tokens, readOnly, notifyTokens]);

  const removeToken = useCallback((tokenId: string) => {
    if (readOnly) return;
    notifyTokens(tokens.filter(t => t.id !== tokenId));
    if (selectedToken === tokenId) setSelectedToken(null);
  }, [tokens, selectedToken, readOnly, notifyTokens]);

  const updateToken = useCallback((tokenId: string, updates: Partial<MapToken>) => {
    if (readOnly) return;
    notifyTokens(tokens.map(t => t.id === tokenId ? { ...t, ...updates } : t));
  }, [tokens, readOnly, notifyTokens]);

  // ── Fog of War ──
  const toggleFogReveal = useCallback((gx: number, gy: number) => {
    if (readOnly) return;
    const size = 3; // 3x3 reveal
    const rx = Math.max(0, gx - 1);
    const ry = Math.max(0, gy - 1);
    const rw = Math.min(size, gridWidth - rx);
    const rh = Math.min(size, gridHeight - ry);

    // Check if this area is already revealed
    const existingIndex = fogOfWar.findIndex(f =>
      f.x === rx && f.y === ry && f.width === rw && f.height === rh
    );

    let newFog: FogReveal[];
    if (existingIndex >= 0) {
      newFog = fogOfWar.filter((_, i) => i !== existingIndex);
    } else {
      newFog = [...fogOfWar, { id: uid("fog"), x: rx, y: ry, width: rw, height: rh }];
    }
    notifyFog(newFog);
  }, [fogOfWar, gridWidth, gridHeight, readOnly, notifyFog]);

  const clearAllFog = useCallback(() => {
    if (readOnly) return;
    notifyFog([]);
  }, [readOnly, notifyFog]);

  // ── Mouse Handlers ──
  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    if (e.button === 1 || (e.button === 0 && e.shiftKey)) {
      setIsPanning(true);
      setPanStart({ x: e.clientX - pan.x, y: e.clientY - pan.y });
      e.preventDefault();
    }
  }, [pan]);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (isPanning) {
      setPan({ x: e.clientX - panStart.x, y: e.clientY - panStart.y });
      return;
    }

    const coords = toGridCoords(e.clientX, e.clientY);
    setHoveredCell(coords);

    if (draggingToken) {
      const token = tokens.find(t => t.id === draggingToken);
      if (token && coords) {
        if (coords.x >= 0 && coords.x + token.size <= gridWidth &&
            coords.y >= 0 && coords.y + token.size <= gridHeight) {
          setTokens(prev => prev.map(t =>
            t.id === draggingToken ? { ...t, x: coords.x, y: coords.y } : t
          ));
        }
      }
    }
  }, [isPanning, panStart, toGridCoords, draggingToken, tokens, gridWidth, gridHeight]);

  const handleMouseUp = useCallback(() => {
    if (draggingToken) {
      const draggedToken = tokens.find(t => t.id === draggingToken);
      if (draggedToken) {
        onTokensChange?.(tokens);
      }
      setDraggingToken(null);
    }
    setIsPanning(false);
  }, [draggingToken, tokens, onTokensChange]);

  const handleClick = useCallback((e: React.MouseEvent) => {
    if (e.button !== 0 || isPanning || draggingToken) return;
    const coords = toGridCoords(e.clientX, e.clientY);
    if (!coords) return;

    const existing = tokenAt(coords.x, coords.y);
    if (existing) {
      setSelectedToken(existing.id);
    } else {
      if (!readOnly) addTokenAt(coords.x, coords.y);
    }
  }, [toGridCoords, tokenAt, isPanning, draggingToken, readOnly, addTokenAt]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    e.preventDefault();
    const delta = e.deltaY > 0 ? -0.1 : 0.1;
    setZoom(prev => Math.max(0.25, Math.min(3, prev + delta)));
  }, []);

  // ── Keyboard Shortcuts ──
  useEffect(() => {
    if (readOnly) return;
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Delete" || e.key === "Backspace") {
        if (selectedToken) {
          removeToken(selectedToken);
          setSelectedToken(null);
        }
      }
    };
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, [selectedToken, removeToken, readOnly]);

  // ── Token Drag Start ──
  const handleTokenMouseDown = useCallback((e: React.MouseEvent, tokenId: string) => {
    if (readOnly) return;
    e.stopPropagation();
    setDraggingToken(tokenId);
    setSelectedToken(tokenId);
  }, [readOnly]);

  // ── Computed canvas dimensions ──
  const canvasWidth = gridWidth * cellSize;
  const canvasHeight = gridHeight * cellSize;

  // ── Selected token detail for inline editing ──
  const selectedTokenData = useMemo(() => {
    return tokens.find(t => t.id === selectedToken) ?? null;
  }, [tokens, selectedToken]);

  return (
    <div className="space-y-4">
      {/* Toolbar */}
      <div className="flex items-center justify-between rounded-lg border border-surface-700 bg-surface-850 px-3 py-2">
        <div className="flex items-center gap-2">
          <Button size="xs" variant="secondary" onClick={() => setZoom(z => Math.min(3, z + 0.25))}>🔍+</Button>
          <span className="text-xs text-surface-400 w-10 text-center">{Math.round(zoom * 100)}%</span>
          <Button size="xs" variant="secondary" onClick={() => setZoom(z => Math.max(0.25, z - 0.25))}>🔍−</Button>
          <Button size="xs" variant="secondary" onClick={() => { setZoom(1); setPan({ x: 0, y: 0 }); }}>Reset</Button>
          <div className="mx-2 h-4 w-px bg-surface-700" />
          <Button size="xs" variant={showGrid ? "secondary" : "ghost"} onClick={() => setShowGrid(o => !o)}>Grid</Button>
          <Button size="xs" variant={showFog ? "secondary" : "ghost"} onClick={() => setShowFog(o => !o)}>Fog</Button>
          {!readOnly && (
            <>
              <Button size="xs" variant="ghost" onClick={clearAllFog}>Clear Fog</Button>
              <div className="mx-2 h-4 w-px bg-surface-700" />
              <span className="text-[11px] text-surface-500">{tokens.length} tokens · {fogOfWar.length} fog reveals</span>
            </>
          )}
        </div>
        <div className="flex items-center gap-2">
          {!readOnly && <span className="text-[10px] text-surface-600">Click to place · Drag tokens · Shift+click to pan · Scroll to zoom</span>}
        </div>
      </div>

      {/* Canvas Container */}
      <div
        ref={canvasRef}
        className={`relative overflow-hidden rounded-xl border ${selectedToken ? "border-accent-500/50" : "border-surface-700"} bg-surface-900`}
        style={{ minHeight: `${Math.min(canvasHeight * zoom + 40, 600)}px`, maxHeight: "70vh", cursor: isPanning ? "grabbing" : draggingToken ? "grabbing" : "default" }}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onClick={handleClick}
        onWheel={handleWheel}
      >
        {/* Transformed Canvas */}
        <div
          style={{
            transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
            transformOrigin: "0 0",
            width: canvasWidth,
            height: canvasHeight,
            position: "relative",
          }}
        >
          {/* Background Image */}
          {imageUrl && (
            <img
              src={imageUrl}
              alt="Map"
              className="pointer-events-none absolute inset-0 h-full w-full object-cover opacity-70"
              style={{ objectFit: "cover" }}
              draggable={false}
            />
          )}

          {/* Grid Cells */}
          {showGrid && (
            <div
              className="absolute inset-0"
              style={{
                display: "grid",
                gridTemplateColumns: `repeat(${gridWidth}, ${cellSize}px)`,
                gridTemplateRows: `repeat(${gridHeight}, ${cellSize}px)`,
              }}
            >
              {Array.from({ length: gridWidth * gridHeight }).map((_, i) => {
                const gx = i % gridWidth;
                const gy = Math.floor(i / gridWidth);
                const isHovered = hoveredCell?.x === gx && hoveredCell?.y === gy;
                const isOccupied = tokenAt(gx, gy);
                return (
                  <div
                    key={i}
                    className={`border-[0.5px] transition-colors ${
                      isHovered && !isOccupied && !readOnly
                        ? "bg-accent-500/20 border-accent-500/40"
                        : "border-surface-700/30"
                    }`}
                    style={{ width: cellSize, height: cellSize }}
                  />
                );
              })}
            </div>
          )}

          {/* Fog of War (dark overlay) */}
          {showFog && fogOfWar.length > 0 && (
            <div className="absolute inset-0 pointer-events-none" style={{ zIndex: 5 }}>
              <svg width={canvasWidth} height={canvasHeight} className="absolute inset-0">
                <defs>
                  <mask id={`fog-mask-${map.id}`}>
                    <rect width={canvasWidth} height={canvasHeight} fill="black" />
                    {fogOfWar.map(fog => (
                      <rect
                        key={fog.id}
                        x={fog.x * cellSize}
                        y={fog.y * cellSize}
                        width={fog.width * cellSize}
                        height={fog.height * cellSize}
                        fill="white"
                      />
                    ))}
                  </mask>
                </defs>
                <rect
                  width={canvasWidth}
                  height={canvasHeight}
                  fill="rgba(0,0,0,0.75)"
                  mask={`url(#fog-mask-${map.id})`}
                />
              </svg>
            </div>
          )}

          {/* Fog of War labels */}
          {showFog && fogOfWar.map(fog => fog.label && (
            <div
              key={`label-${fog.id}`}
              className="absolute pointer-events-none text-[9px] text-surface-500 font-semibold uppercase tracking-wider"
              style={{
                left: fog.x * cellSize + 4,
                top: fog.y * cellSize + 4,
                zIndex: 6,
              }}
            >
              {fog.label}
            </div>
          ))}

          {/* Tokens */}
          {tokens.filter(t => t.visible || !readOnly).map((token) => {
            const isSelected = selectedToken === token.id;
            const isDragging = draggingToken === token.id;
            const tokenSize = token.size * cellSize;
            return (
              <div
                key={token.id}
                className={`absolute flex items-center justify-center rounded-full border-2 shadow-lg transition-shadow cursor-grab ${
                  isSelected ? "border-accent-400 shadow-accent-500/30" : "border-white/30"
                } ${isDragging ? "shadow-xl scale-110 z-50" : "z-10"} ${!token.visible ? "opacity-40" : ""}`}
                style={{
                  left: token.x * cellSize,
                  top: token.y * cellSize,
                  width: tokenSize,
                  height: tokenSize,
                  backgroundColor: token.color || "#8b30ff",
                  transform: "translate(-50%, -50%)",
                  zIndex: isDragging ? 50 : isSelected ? 20 : 10,
                }}
                onMouseDown={(e) => handleTokenMouseDown(e, token.id)}
                title={`${token.label} (${token.x}, ${token.y})`}
              >
                {/* Token Portrait */}
                {token.portraitUrl ? (
                  <img
                    src={token.portraitUrl}
                    alt={token.label}
                    className="h-full w-full rounded-full object-cover"
                    draggable={false}
                  />
                ) : (
                  <span className="text-xs font-bold text-white drop-shadow-sm select-none">
                    {token.type === "player" ? "⚔" : token.type === "enemy" ? "💀" : token.type === "npc" ? "👤" : "?"}
                  </span>
                )}

                {/* HP overlay */}
                {token.hp && (
                  <div
                    className="absolute -bottom-1 left-1/2 -translate-x-1/2 rounded-full bg-surface-900/90 px-1.5 py-0.5 text-[9px] font-bold text-white whitespace-nowrap shadow"
                    style={{ zIndex: 30 }}
                  >
                    {token.hp.current}/{token.hp.max}
                  </div>
                )}

                {/* Label */}
                <div
                  className="absolute -top-5 left-1/2 -translate-x-1/2 rounded bg-surface-900/80 px-1.5 py-0.5 text-[9px] font-medium text-white whitespace-nowrap"
                  style={{ zIndex: 30 }}
                >
                  {token.label}
                </div>
              </div>
            );
          })}

          {/* Hover cell indicator */}
          {hoveredCell && !tokenAt(hoveredCell.x, hoveredCell.y) && !readOnly && (
            <div
              className="absolute border-2 border-dashed border-accent-500/60 bg-accent-500/10 pointer-events-none z-10"
              style={{
                left: hoveredCell.x * cellSize,
                top: hoveredCell.y * cellSize,
                width: cellSize,
                height: cellSize,
              }}
            />
          )}
        </div>
      </div>

      {/* Selected Token Editor */}
      {selectedTokenData && !readOnly && (
        <div className="rounded-xl border border-surface-700 bg-surface-850 p-4 space-y-3">
          <div className="flex items-center justify-between">
            <h4 className="text-xs font-semibold uppercase tracking-wider text-surface-400">
              Token: <span className="text-surface-100">{selectedTokenData.label}</span>
            </h4>
            <Button size="xs" variant="danger" onClick={() => removeToken(selectedTokenData.id)}>
              Remove Token
            </Button>
          </div>
          <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
            <div>
              <label className="block text-[10px] text-surface-500 mb-0.5">Label</label>
              <input
                value={selectedTokenData.label}
                onChange={(e) => updateToken(selectedTokenData.id, { label: e.target.value })}
                className="w-full rounded-md border border-surface-700 bg-surface-800 px-2 py-1.5 text-xs text-surface-100 focus:border-accent-500 focus:outline-none"
              />
            </div>
            <div>
              <label className="block text-[10px] text-surface-500 mb-0.5">Type</label>
              <select
                value={selectedTokenData.type}
                onChange={(e) => updateToken(selectedTokenData.id, { type: e.target.value as MapToken["type"] })}
                className="w-full rounded-md border border-surface-700 bg-surface-800 px-2 py-1.5 text-xs text-surface-100 focus:border-accent-500 focus:outline-none"
              >
                <option value="player">Player</option>
                <option value="enemy">Enemy</option>
                <option value="npc">NPC</option>
                <option value="custom">Custom</option>
              </select>
            </div>
            <div>
              <label className="block text-[10px] text-surface-500 mb-0.5">Color</label>
              <div className="flex gap-1">
                {["#8b30ff", "#3b82f6", "#27ae60", "#f39c12", "#e74c3c", "#c0392b", "#1abc9c", "#9b59b6"].map(c => (
                  <button
                    key={c}
                    onClick={() => updateToken(selectedTokenData.id, { color: c })}
                    className={`h-6 w-6 rounded-full border-2 transition-all ${selectedTokenData.color === c ? "border-white scale-110" : "border-transparent"}`}
                    style={{ backgroundColor: c }}
                  />
                ))}
              </div>
            </div>
            <div>
              <label className="block text-[10px] text-surface-500 mb-0.5">Size</label>
              <select
                value={selectedTokenData.size}
                onChange={(e) => updateToken(selectedTokenData.id, { size: parseInt(e.target.value) })}
                className="w-full rounded-md border border-surface-700 bg-surface-800 px-2 py-1.5 text-xs text-surface-100 focus:border-accent-500 focus:outline-none"
              >
                {[1, 2, 3, 4].map(s => (
                  <option key={s} value={s}>{s}×{s} ({["Medium", "Large", "Huge", "Gargantuan"][s - 1]})</option>
                ))}
              </select>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
            <div>
              <label className="block text-[10px] text-surface-500 mb-0.5">Position X</label>
              <input
                type="number"
                min={0}
                max={gridWidth - 1}
                value={selectedTokenData.x}
                onChange={(e) => updateToken(selectedTokenData.id, { x: parseInt(e.target.value) || 0 })}
                className="w-full rounded-md border border-surface-700 bg-surface-800 px-2 py-1.5 text-xs text-surface-100 text-center focus:border-accent-500 focus:outline-none"
              />
            </div>
            <div>
              <label className="block text-[10px] text-surface-500 mb-0.5">Position Y</label>
              <input
                type="number"
                min={0}
                max={gridHeight - 1}
                value={selectedTokenData.y}
                onChange={(e) => updateToken(selectedTokenData.id, { y: parseInt(e.target.value) || 0 })}
                className="w-full rounded-md border border-surface-700 bg-surface-800 px-2 py-1.5 text-xs text-surface-100 text-center focus:border-accent-500 focus:outline-none"
              />
            </div>
            <div>
              <label className="block text-[10px] text-surface-500 mb-0.5">Portrait URL</label>
              <input
                value={selectedTokenData.portraitUrl || ""}
                onChange={(e) => updateToken(selectedTokenData.id, { portraitUrl: e.target.value || undefined })}
                placeholder="URL or /images/tokens/..."
                className="w-full rounded-md border border-surface-700 bg-surface-800 px-2 py-1.5 text-xs text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none"
              />
            </div>
            <div className="flex items-center gap-2 pt-4">
              <label className="flex cursor-pointer items-center gap-1.5">
                <input
                  type="checkbox"
                  checked={selectedTokenData.visible}
                  onChange={(e) => updateToken(selectedTokenData.id, { visible: e.target.checked })}
                  className="h-4 w-4 rounded border-surface-600 bg-surface-800 accent-accent-500"
                />
                <span className="text-xs text-surface-300">Visible</span>
              </label>
            </div>
          </div>
          {selectedTokenData.hp && (
            <div className="flex items-center gap-3 pt-1 border-t border-surface-700">
              <span className="text-xs text-surface-400">HP:</span>
              <input
                type="number"
                value={selectedTokenData.hp.current}
                onChange={(e) => updateToken(selectedTokenData.id, { hp: { ...selectedTokenData.hp!, current: parseInt(e.target.value) || 0 } })}
                className="w-16 rounded-md border border-surface-700 bg-surface-800 px-2 py-1 text-xs text-surface-100 text-center focus:border-accent-500 focus:outline-none"
              />
              <span className="text-xs text-surface-500">/ {selectedTokenData.hp.max}</span>
              <Button size="xs" variant="danger" onClick={() => updateToken(selectedTokenData.id, { hp: { current: Math.max(0, selectedTokenData.hp!.current - 5), max: selectedTokenData.hp!.max } })}>−5</Button>
              <Button size="xs" variant="secondary" onClick={() => updateToken(selectedTokenData.id, { hp: { current: Math.min(selectedTokenData.hp!.max, selectedTokenData.hp!.current + 5), max: selectedTokenData.hp!.max } })}>+5</Button>
            </div>
          )}
          {!selectedTokenData.hp && !readOnly && (
            <div className="pt-1">
              <Button size="xs" variant="ghost" onClick={() => updateToken(selectedTokenData.id, { hp: { current: 20, max: 20 } })}>+ Add HP</Button>
            </div>
          )}
        </div>
      )}

      {/* Token Legend */}
      <div className="rounded-lg border border-surface-700 bg-surface-850 p-3">
        <div className="flex items-center justify-between">
          <h4 className="text-[10px] font-semibold uppercase tracking-wider text-surface-500">Token Legend</h4>
          <span className="text-[10px] text-surface-500">{tokens.length} on map</span>
        </div>
        <div className="mt-2 flex flex-wrap gap-2">
          {tokens.map(token => (
            <button
              key={token.id}
              onClick={() => setSelectedToken(token.id)}
              className={`flex items-center gap-1.5 rounded-md px-2 py-1 text-[11px] transition-all ${
                selectedToken === token.id ? "ring-1 ring-accent-500 bg-accent-500/10" : "bg-surface-800 hover:bg-surface-700"
              }`}
            >
              <span className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: token.color || "#8b30ff" }} />
              <span className="text-surface-300">{token.label}</span>
              {!token.visible && <span className="text-warrior-400 text-[9px]">👁</span>}
            </button>
          ))}
        </div>
      </div>

      {/* Instructions */}
      {readOnly && (
        <p className="text-xs text-surface-500 text-center italic">
          Viewing mode — tokens and fog are read-only.
        </p>
      )}
    </div>
  );
}
