{"content": "/* ── Map Form ──────────────────────────────────────────────────
 * Modal form for creating or editing a battle map.
 * ─────────────────────────────────────────────────────────────── */

import { useState } from "react";
import { Button } from "@/components/ui/Button";
import type { BattleMap, MapToken } from "@/types";

function uid(prefix: string): string {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

interface MapFormProps {
  initialData?: BattleMap;
  onSubmit: (map: BattleMap) => void;
  onCancel: () => void;
}

export function MapForm({ initialData, onSubmit, onCancel }: MapFormProps) {
  const [name, setName] = useState(initialData?.name ?? "");
  const [imageUrl, setImageUrl] = useState(initialData?.imageUrl ?? "");
  const [gridWidth, setGridWidth] = useState(initialData?.gridWidth ?? 24);
  const [gridHeight, setGridHeight] = useState(initialData?.gridHeight ?? 18);
  const [gridSize, setGridSize] = useState(initialData?.gridSize ?? 50);
  const [gridColor, setGridColor] = useState(initialData?.gridColor ?? "#444");
  const [notes, setNotes] = useState(initialData?.notes ?? "");

  const handleSubmit = () => {
    if (!name.trim()) return;

    const map: BattleMap = {
      id: initialData?.id ?? uid("map"),
      name: name.trim(),
      imageUrl: imageUrl.trim() || undefined,
      imageFit: "cover",
      gridWidth: Math.max(4, Math.min(100, gridWidth)),
      gridHeight: Math.max(4, Math.min(100, gridHeight)),
      gridSize: Math.max(20, Math.min(200, gridSize)),
      gridColor,
      fogOfWar: initialData?.fogOfWar ?? [],
      tokens: initialData?.tokens ?? [],
      notes: notes.trim() || undefined,
      createdAt: initialData?.createdAt ?? Date.now(),
      updatedAt: Date.now(),
    };

    onSubmit(map);
  };

  return (
    <div className="space-y-5">
      <div>
        <label className="mb-1 block text-xs font-medium text-surface-400">Map Name</label>
        <input value={name} onChange={(e) => setName(e.target.value)} placeholder="e.g. Merchant's Way Crossroads"
          className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none" />
      </div>

      <div>
        <label className="mb-1 block text-xs font-medium text-surface-400">Map Image URL (optional)</label>
        <input value={imageUrl} onChange={(e) => setImageUrl(e.target.value)} placeholder="Paste a URL to a map image..."
          className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none" />
        {imageUrl && (
          <div className="mt-2 overflow-hidden rounded-lg border border-surface-700 max-h-32">
            <img src={imageUrl} alt="Map preview" className="w-full object-cover" onError={(e) => { (e.target as HTMLImageElement).style.display = "none"; }} />
          </div>
        )}
      </div>

      <div className="grid grid-cols-3 gap-3">
        <div>
          <label className="mb-1 block text-xs font-medium text-surface-400">Grid Width</label>
          <input type="number" min={4} max={100} value={gridWidth} onChange={(e) => setGridWidth(parseInt(e.target.value) || 24)}
            className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 text-center focus:border-accent-500 focus:outline-none" />
        </div>
        <div>
          <label className="mb-1 block text-xs font-medium text-surface-400">Grid Height</label>
          <input type="number" min={4} max={100} value={gridHeight} onChange={(e) => setGridHeight(parseInt(e.target.value) || 18)}
            className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 text-center focus:border-accent-500 focus:outline-none" />
        </div>
        <div>
          <label className="mb-1 block text-xs font-medium text-surface-400">Cell Size (px)</label>
          <input type="number" min={20} max={200} value={gridSize} onChange={(e) => setGridSize(parseInt(e.target.value) || 50)}
            className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 text-center focus:border-accent-500 focus:outline-none" />
        </div>
      </div>

      <div>
        <label className="mb-1 block text-xs font-medium text-surface-400">Grid Color</label>
        <div className="flex gap-2 items-center">
          <input type="color" value={gridColor} onChange={(e) => setGridColor(e.target.value)}
            className="h-8 w-8 cursor-pointer rounded border border-surface-700 bg-surface-800" />
          <span className="text-xs text-surface-500">{gridColor}</span>
        </div>
      </div>

      <div>
        <label className="mb-1 block text-xs font-medium text-surface-400">DM Notes</label>
        <textarea value={notes} onChange={(e) => setNotes(e.target.value)} rows={3} placeholder="Terrain features, traps, secret doors..."
          className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none resize-none" />
      </div>

      <div className="flex justify-end gap-3 pt-2 border-t border-surface-700">
        <Button variant="ghost" onClick={onCancel}>Cancel</Button>
        <Button onClick={handleSubmit} disabled={!name.trim()}>
          {initialData ? "Update Map" : "Create Map"}
        </Button>
      </div>
    </div>
  );
}
