{"content": "/* ── Media Carousel ─────────────────────────────────────────────
 * A reusable image carousel/browser that scans the public/images/
 * directories for battlemaps, tokens, and portraits.
 * ─────────────────────────────────────────────────────────────── */

import { useState, useMemo, useCallback, useEffect } from "react";
import { Button } from "@/components/ui/Button";

export type MediaCategory = "battlemaps" | "tokens" | "portrait";

export interface MediaAsset {
  /** Relative path from public/, e.g. "/images/battlemaps/dungeon_01.png" */
  path: string;
  /** Filename without extension, e.g. "dungeon_01" */
  name: string;
  /** The category folder it lives in */
  category: MediaCategory;
  /** File extension */
  ext: string;
}

interface MediaCarouselProps {
  /** Which category to show */
  category: MediaCategory;
  /** Currently selected path */
  selectedPath?: string;
  /** Called when user picks an image */
  onSelect: (asset: MediaAsset) => void;
  /** Called to close/dismiss the picker */
  onClose: () => void;
}

/**
 * Known image assets. In a production app, these would be fetched from
 * a server endpoint or scanned at build time. Since we use Vite's public/
 * directory, we maintain a curated registry here that the DM populates.
 *
 * To add new images, simply drop files into the corresponding folder and
 * add an entry to this registry. The carousel will display them.
 */
const KNOWN_ASSETS: MediaAsset[] = [
  // ── Battlemaps ──
  { path: "/images/battlemaps/dungeon_01.png", name: "Dungeon Hall", category: "battlemaps", ext: "png" },
  { path: "/images/battlemaps/forest_clearing.png", name: "Forest Clearing", category: "battlemaps", ext: "png" },
  { path: "/images/battlemaps/cavern_01.png", name: "Cavern Depths", category: "battlemaps", ext: "png" },
  { path: "/images/battlemaps/tavern_brawl.png", name: "Tavern Brawl", category: "battlemaps", ext: "png" },
  { path: "/images/battlemaps/crossroads.png", name: "Crossroads", category: "battlemaps", ext: "png" },
  { path: "/images/battlemaps/throne_room.png", name: "Throne Room", category: "battlemaps", ext: "png" },

  // ── Tokens ──
  { path: "/images/tokens/hero_01.png", name: "Hero Token (Gold)", category: "tokens", ext: "png" },
  { path: "/images/tokens/hero_02.png", name: "Hero Token (Blue)", category: "tokens", ext: "png" },
  { path: "/images/tokens/enemy_01.png", name: "Enemy Token (Red)", category: "tokens", ext: "png" },
  { path: "/images/tokens/enemy_02.png", name: "Enemy Token (Dark)", category: "tokens", ext: "png" },
  { path: "/images/tokens/npc_01.png", name: "NPC Token (Green)", category: "tokens", ext: "png" },
  { path: "/images/tokens/boss_01.png", name: "Boss Token (Purple)", category: "tokens", ext: "png" },

  // ── Portraits ──
  { path: "/images/portrait/dwarf_fighter.png", name: "Dwarf Fighter", category: "portrait", ext: "png" },
  { path: "/images/portrait/elf_wizard.png", name: "Elf Wizard", category: "portrait", ext: "png" },
  { path: "/images/portrait/tabaxi_rogue.png", name: "Tabaxi Rogue", category: "portrait", ext: "png" },
  { path: "/images/portrait/aasimar_cleric.png", name: "Aasimar Cleric", category: "portrait", ext: "png" },
  { path: "/images/portrait/human_ranger.png", name: "Human Ranger", category: "portrait", ext: "png" },
  { path: "/images/portrait/halfling_bard.png", name: "Halfling Bard", category: "portrait", ext: "png" },
  { path: "/images/portrait/dragonborn_sorcerer.png", name: "Dragonborn Sorcerer", category: "portrait", ext: "png" },
  { path: "/images/portrait/half_orc_barbarian.png", name: "Half-Orc Barbarian", category: "portrait", ext: "png" },
];

const CATEGORY_LABELS: Record<MediaCategory, string> = {
  battlemaps: "Battle Maps",
  tokens: "Tokens",
  portrait: "Portraits",
};

const CATEGORY_ICONS: Record<MediaCategory, string> = {
  battlemaps: "🗺",
  tokens: "🔘",
  portrait: "🖼",
};

export function MediaCarousel({ category, selectedPath, onSelect, onClose }: MediaCarouselProps) {
  const [searchQuery, setSearchQuery] = useState("");
  const [previewAsset, setPreviewAsset] = useState<MediaAsset | null>(null);

  const filtered = useMemo(() => {
    const catAssets = KNOWN_ASSETS.filter(a => a.category === category);
    if (!searchQuery.trim()) return catAssets;
    const q = searchQuery.toLowerCase();
    return catAssets.filter(a => a.name.toLowerCase().includes(q));
  }, [category, searchQuery]);

  const handleSelect = useCallback((asset: MediaAsset) => {
    onSelect(asset);
    onClose();
  }, [onSelect, onClose]);

  // Keyboard escape to close
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        if (previewAsset) setPreviewAsset(null);
        else onClose();
      }
    };
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, [onClose, previewAsset]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
      <div className="w-full max-w-3xl rounded-xl border border-surface-700 bg-surface-850 shadow-2xl animate-in zoom-in-95 fade-in duration-200">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-surface-700 px-5 py-4">
          <div className="flex items-center gap-2">
            <span className="text-lg">{CATEGORY_ICONS[category]}</span>
            <h2 className="text-lg font-semibold text-surface-100">
              Select {CATEGORY_LABELS[category]}
            </h2>
            <span className="rounded-full bg-surface-800 px-2 py-0.5 text-[11px] text-surface-400">
              {filtered.length} asset{filtered.length !== 1 ? "s" : ""}
            </span>
          </div>
          <button
            onClick={onClose}
            className="flex h-7 w-7 items-center justify-center rounded-md text-surface-400 hover:bg-surface-700 hover:text-surface-200"
            aria-label="Close"
          >
            ✕
          </button>
        </div>

        {/* Search */}
        <div className="px-5 py-3 border-b border-surface-700/50">
          <div className="relative">
            <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-surface-500 text-sm">🔍</span>
            <input
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search assets..."
              className="w-full rounded-lg border border-surface-700 bg-surface-800 py-2 pl-9 pr-3 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none"
            />
          </div>
        </div>

        {/* Grid */}
        <div className="max-h-[50vh] overflow-y-auto p-5">
          {filtered.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12">
              <span className="text-4xl text-surface-600 mb-3">📁</span>
              <p className="text-sm text-surface-500 text-center">
                {searchQuery
                  ? `No assets matching "${searchQuery}".`
                  : `No ${CATEGORY_LABELS[category].toLowerCase()} yet. Add images to public/images/${category}/`}
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-3 gap-3 sm:grid-cols-4 md:grid-cols-5">
              {filtered.map((asset) => {
                const isSelected = selectedPath === asset.path;
                return (
                  <button
                    key={asset.path}
                    onClick={() => handleSelect(asset)}
                    onMouseEnter={() => setPreviewAsset(asset)}
                    onMouseLeave={() => setPreviewAsset(null)}
                    className={`group relative flex flex-col items-center gap-1.5 rounded-lg border-2 p-2 transition-all ${
                      isSelected
                        ? "border-accent-500 bg-accent-500/10 shadow-md"
                        : "border-surface-700 bg-surface-800 hover:border-surface-600 hover:bg-surface-750"
                    }`}
                  >
                    {/* Thumbnail */}
                    <div className="flex aspect-square w-full items-center justify-center rounded-md bg-surface-900 overflow-hidden">
                      <img
                        src={asset.path}
                        alt={asset.name}
                        className="h-full w-full object-cover transition-transform group-hover:scale-105"
                        onError={(e) => {
                          // Show placeholder on load failure
                          (e.target as HTMLImageElement).style.display = "none";
                          (e.target as HTMLImageElement).parentElement!.innerHTML = `<span class="text-2xl text-surface-500">${CATEGORY_ICONS[category]}</span>`;
                        }}
                      />
                    </div>
                    {/* Name */}
                    <span className={`text-[10px] font-medium text-center leading-tight line-clamp-2 ${
                      isSelected ? "text-accent-300" : "text-surface-400"
                    }`}>
                      {asset.name}
                    </span>
                    {/* Selected indicator */}
                    {isSelected && (
                      <span className="absolute -right-1 -top-1 flex h-5 w-5 items-center justify-center rounded-full bg-accent-500 text-[10px] text-white shadow">
                        ✓
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between border-t border-surface-700 px-5 py-3">
          <p className="text-[11px] text-surface-500">
            Assets from <code className="text-surface-400 bg-surface-800 px-1 rounded">/images/{category}/</code>
          </p>
          <Button size="xs" variant="ghost" onClick={onClose}>
            Cancel
          </Button>
        </div>
      </div>

      {/* Preview popup */}
      {previewAsset && (
        <div className="fixed bottom-6 right-6 z-[60] rounded-xl border border-surface-700 bg-surface-850 p-3 shadow-2xl animate-in slide-in-from-bottom-4 fade-in duration-200">
          <img
            src={previewAsset.path}
            alt={previewAsset.name}
            className="h-32 w-32 rounded-lg object-cover"
            onError={(e) => { (e.target as HTMLImageElement).style.display = "none"; }}
          />
          <p className="mt-1 text-[10px] text-surface-400 text-center">{previewAsset.name}</p>
        </div>
      )}
    </div>
  );
}

/**
 * Hook to open the MediaCarousel from any component.
 * Returns a tuple: [showCarousel props | null, open function]
 */
export function useMediaCarousel() {
  const [state, setState] = useState<{
    category: MediaCategory;
    selectedPath?: string;
    onSelect: (asset: MediaAsset) => void;
  } | null>(null);

  const open = useCallback(
    (category: MediaCategory, opts?: { selectedPath?: string; onSelect?: (asset: MediaAsset) => void }) => {
      return new Promise<MediaAsset | null>((resolve) => {
        setState({
          category,
          selectedPath: opts?.selectedPath,
          onSelect: (asset: MediaAsset) => {
            opts?.onSelect?.(asset);
            resolve(asset);
          },
        });
      });
    },
    [],
  );

  const close = useCallback(() => {
    setState(null);
  }, []);

  return { carouselState: state, openCarousel: open, closeCarousel: close };
}
